```typescript
export type AquaticFarmState =
  | { status: "none" }
  | { status: "provisioned"; id: string; region: string }
  | { status: "active"; id: string; region: string; activatedAt: string }
  | { status: "decommissioned"; id: string; reason: string };

export type AquaticFarmCommand =
  | { type: "provision"; id: string; region: string }
  | { type: "activate"; at: string }
  | { type: "decommission"; reason: string };

export type AquaticFarmEvent =
  | { type: "AquaticFarmProvisioned"; id: string; region: string }
  | { type: "AquaticFarmActivated"; at: string }
  | { type: "AquaticFarmDecommissioned"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const aquaticFarmDecider: Decider<AquaticFarmCommand, AquaticFarmEvent, AquaticFarmState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "provision":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "AquaticFarmProvisioned", id: command.id, region: command.region }];
      case "activate":
        if (state.status === "decommissioned") throw new DomainError("DECOMMISSIONED");
        if (state.status !== "provisioned") throw new DomainError("NOT_PROVISIONED");
        return [{ type: "AquaticFarmActivated", at: command.at }];
      case "decommission":
        if (state.status === "decommissioned" || state.status === "none") throw new DomainError("BAD_STATE");
        return [{ type: "AquaticFarmDecommissioned", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "AquaticFarmProvisioned":
        return { status: "provisioned", id: event.id, region: event.region };
      case "AquaticFarmActivated":
        if (state.status !== "provisioned") return state;
        return { status: "active", id: state.id, region: state.region, activatedAt: event.at };
      case "AquaticFarmDecommissioned":
        if (state.status === "none" || state.status === "decommissioned") return state;
        return { status: "decommissioned", id: state.id, reason: event.reason };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
