export type NetPenState =
  | { status: "none" }
  | { status: "installed"; id: string; capacity: number; loaded: number }
  | { status: "retired"; id: string; at: string };

export type NetPenCommand =
  | { type: "install"; id: string; capacity: number }
  | { type: "load"; count: number }
  | { type: "inspect"; by: string }
  | { type: "retire"; at: string };

export type NetPenEvent =
  | { type: "NetPenInstalled"; id: string; capacity: number }
  | { type: "NetPenLoaded"; count: number }
  | { type: "NetPenInspected"; by: string }
  | { type: "NetPenRetired"; at: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const netPenDecider: Decider<NetPenCommand, NetPenEvent, NetPenState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "install":
        if (state.status !== "none") throw new DomainError("EXISTS");
        return [{ type: "NetPenInstalled", id: command.id, capacity: command.capacity }];
      case "load":
        if (state.status === "retired") throw new DomainError("RETIRED");
        if (state.status !== "installed") throw new DomainError("NOT_INSTALLED");
        if (state.loaded + command.count > state.capacity) throw new DomainError("OVER_CAPACITY");
        return [{ type: "NetPenLoaded", count: command.count }];
      case "inspect":
        if (state.status !== "installed") throw new DomainError("NOT_INSTALLED");
        return [{ type: "NetPenInspected", by: command.by }];
      case "retire":
        if (state.status !== "installed") throw new DomainError("BAD_STATE");
        return [{ type: "NetPenRetired", at: command.at }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "NetPenInstalled":
        return { status: "installed", id: event.id, capacity: event.capacity, loaded: 0 };
      case "NetPenLoaded":
        if (state.status !== "installed") return state;
        return { ...state, loaded: state.loaded + event.count };
      case "NetPenInspected":
        return state;
      case "NetPenRetired":
        if (state.status !== "installed") return state;
        return { status: "retired", id: state.id, at: event.at };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
