  | { type: "extend"; newEndsAt: string }
  | { type: "close"; at: string }
  | { type: "cancel"; reason: string };

export type HarvestWindowEvent =
  | { type: "HarvestWindowOpened"; id: string; startsAt: string; endsAt: string }
  | { type: "HarvestWindowExtended"; newEndsAt: string }
  | { type: "HarvestWindowClosed"; at: string }
  | { type: "HarvestWindowCancelled"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) {
    super(code);
    this.name = "DomainError";
  }
