```typescript
export type HarvestWindowEvent =
  | { type: "HarvestWindowOpened"; id: string; farmId: string; startsAt: string }
  | { type: "HarvestWindowExtended"; id: string; newEndsAt: string }
  | { type: "HarvestWindowClosed"; id: string; farmId: string }
  | { type: "HarvestWindowCancelled"; id: string; farmId: string; reason: string };

export interface FarmHarvestView {
  readonly activeByFarm: Readonly<Record<string, number>>;
  readonly totalOpened: number;
  readonly totalClosed: number;
}

export const emptyView: FarmHarvestView = {
  activeByFarm: {},
  totalOpened: 0,
  totalClosed: 0,
};

export function project(view: FarmHarvestView, event: HarvestWindowEvent): FarmHarvestView {
  switch (event.type) {
    case "HarvestWindowOpened": {
      const prev = view.activeByFarm[event.farmId] ?? 0;
      return {
        activeByFarm: { ...view.activeByFarm, [event.farmId]: prev + 1 },
        totalOpened: view.totalOpened + 1,
        totalClosed: view.totalClosed,
      };
    }
    case "HarvestWindowExtended":
      return view;
    case "HarvestWindowClosed": {
      const prev = view.activeByFarm[event.farmId] ?? 0;
      return {
        activeByFarm: { ...view.activeByFarm, [event.farmId]: Math.max(0, prev - 1) },
        totalOpened: view.totalOpened,
        totalClosed: view.totalClosed + 1,
      };
    }
    case "HarvestWindowCancelled": {
      const prev = view.activeByFarm[event.farmId] ?? 0;
      return {
        ...view,
        activeByFarm: { ...view.activeByFarm, [event.farmId]: Math.max(0, prev - 1) },
      };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
```

A projection builds a denormalised read model targeted at queries, while evolve reconstructs the aggregate's own state for decision-making. Projections can cross aggregates and often ignore events they don't care about, whereas evolve is exhaustive over the aggregate's own event union.

```typescript
export type WaterQualityEvent =
  | { type: "WaterQualityLogOpened"; id: string }
  | { type: "WaterQualityReadingRecorded"; id: string; ph: number; tempC: number; at: string }
  | { type: "WaterQualityLogClosed"; id: string; at: string };

export interface LatestReading {
  readonly ph: number;
  readonly tempC: number;
  readonly at: string;
}

export interface LatestView {
  readonly byLog: Readonly<Record<string, LatestReading>>;
  readonly closed: ReadonlySet<string>;
}

export const emptyView: LatestView = {
  byLog: {},
  closed: new Set<string>(),
};

export function project(view: LatestView, event: WaterQualityEvent): LatestView {
  switch (event.type) {
    case "WaterQualityLogOpened":
      return view;
    case "WaterQualityReadingRecorded":
      return {
        ...view,
        byLog: {
          ...view.byLog,
          [event.id]: { ph: event.ph, tempC: event.tempC, at: event.at },
        },
      };
    case "WaterQualityLogClosed": {
      const next = new Set(view.closed);
      next.add(event.id);
      return { ...view, closed: next };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
