```typescript
export type SeafoodBatchEvent =
  | { type: "SeafoodBatchCreated"; id: string; weightKg: number }
  | { type: "SeafoodBatchInspected"; id: string; passed: boolean; at: string }
  | { type: "SeafoodBatchRejected"; id: string; reason: string }
  | { type: "SeafoodBatchShipped"; id: string; to: string };

export interface QualityView {
  readonly totalBatches: number;
  readonly passed: number;
  readonly rejected: number;
  readonly rejectReasons: Readonly<Record<string, number>>;
}

export const emptyView: QualityView = {
  totalBatches: 0,
  passed: 0,
  rejected: 0,
  rejectReasons: {},
};

export function project(view: QualityView, event: SeafoodBatchEvent): QualityView {
  switch (event.type) {
    case "SeafoodBatchCreated":
      return { ...view, totalBatches: view.totalBatches + 1 };
    case "SeafoodBatchInspected":
      if (!event.passed) return view;
      return { ...view, passed: view.passed + 1 };
    case "SeafoodBatchRejected": {
      const prev = view.rejectReasons[event.reason] ?? 0;
      return {
        ...view,
        rejected: view.rejected + 1,
        rejectReasons: { ...view.rejectReasons, [event.reason]: prev + 1 },
      };
    }
    case "SeafoodBatchShipped":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}
