```typescript
export const CURRENT_VERSION = 3;

export interface NetPenStateV1 {
  readonly id: string;
  readonly capacity: number;
}

export interface NetPenStateV2 {
  readonly id: string;
  readonly capacity: number;
  readonly loaded: number;
}

export interface NetPenStateV3 {
  readonly id: string;
  readonly capacity: number;
  readonly loaded: number;
  readonly lastInspectedAt: string | null;
}

export type NetPenCurrentState = NetPenStateV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(s: NetPenStateV1): NetPenStateV2 {
  return { ...s, loaded: 0 };
}

function v2Tov3(s: NetPenStateV2): NetPenStateV3 {
  return { ...s, lastInspectedAt: null };
}

function isV1(s: unknown): s is NetPenStateV1 {
  return typeof s === "object" && s !== null && "id" in s && "capacity" in s;
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<NetPenCurrentState> {
  if (raw.version === CURRENT_VERSION) {
    return { version: CURRENT_VERSION, state: raw.state as NetPenCurrentState };
  }
  let version = raw.version;
  let state: unknown = raw.state;
  if (version === 1) {
    if (!isV1(state)) throw new Error("CORRUPT_V1_STATE");
    state = v1Tov2(state);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as NetPenStateV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${raw.version}`);
  return { version: CURRENT_VERSION, state: state as NetPenCurrentState };
}
```

The upgrader chain runs functions keyed on the source version until state reaches CURRENT_VERSION. Each step is a pure transformation of one shape into the next.

```typescript
export const CURRENT_VERSION = 3;

export interface FeedingRegimeV1 {
  readonly id: string;
  readonly kcalPerDay: number;
}

export interface FeedingRegimeV2 {
  readonly id: string;
  readonly kcalPerDay: number;
  readonly feedingsPerDay: number;
}

export interface FeedingRegimeV3 {
  readonly id: string;
  readonly kcalPerDay: number;
  readonly feedingsPerDay: number;
  readonly startedAt: string | null;
}

export type FeedingRegimeCurrent = FeedingRegimeV3;

export interface Snapshot<S> {
  readonly version: number;
  readonly state: S;
}

function v1Tov2(s: FeedingRegimeV1): FeedingRegimeV2 {
  return { ...s, feedingsPerDay: 2 };
}

function v2Tov3(s: FeedingRegimeV2): FeedingRegimeV3 {
  return { ...s, startedAt: null };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<FeedingRegimeCurrent> {
  let version = raw.version;
  let state: unknown = raw.state;
  if (version === 1) {
    state = v1Tov2(state as FeedingRegimeV1);
    version = 2;
  }
  if (version === 2) {
    state = v2Tov3(state as FeedingRegimeV2);
    version = 3;
  }
  if (version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_VERSION_${raw.version}`);
  return { version: CURRENT_VERSION, state: state as FeedingRegimeCurrent };
}
