export type NetPenEvent =
  | { type: "NetPenInstalled"; id: string; capacity: number }
  | { type: "NetPenLoaded"; count: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface AppendOptions {
  readonly expectedRevision: ExpectedRevision;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(stream: string, events: E[], opts: AppendOptions): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: ExpectedRevision) {
    super(`Concurrency conflict on stream ${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export async function appendNetPenEvents(
  store: EventStore,
  streamName: string,
  events: NetPenEvent[],
): Promise<bigint> {
  const current = await store.readStream<NetPenEvent>(streamName);
  try {
    const result = await store.appendToStream<NetPenEvent>(streamName, events, {
      expectedRevision: current.revision,
    });
    return result.nextRevision;
  } catch (err: unknown) {
    if (err instanceof Error && err.message.includes("WrongExpectedVersion")) {
      throw new ConcurrencyConflict(streamName, current.revision);
    }
    throw err;
  }
}
```

Optimistic concurrency lets multiple writers proceed without locks: each appendToStream carries the revision the writer read when loading state. If another writer advanced the stream in the meantime, the server rejects the append, and the client surfaces a typed ConcurrencyConflict so the caller can retry (reload state and re-decide).

