export type FishStockEvent =
  | { type: "FishStockSeeded"; id: string; count: number }
  | { type: "FishStockHarvested"; id: string; count: number };

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, pos: bigint): Promise<void>;
}

export interface EventEnvelope<E> {
  readonly position: bigint;
  readonly event: E;
}

export interface EventSource {
  subscribe(from: bigint | null): AsyncIterable<EventEnvelope<FishStockEvent>>;
}

export interface StockView {
  readonly totals: Readonly<Record<string, number>>;
}

export function projection(view: StockView, event: FishStockEvent): StockView {
  switch (event.type) {
    case "FishStockSeeded": {
      const prev = view.totals[event.id] ?? 0;
      return { totals: { ...view.totals, [event.id]: prev + event.count } };
    }
    case "FishStockHarvested": {
      const prev = view.totals[event.id] ?? 0;
      return { totals: { ...view.totals, [event.id]: prev - event.count } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export async function runSubscription(
  name: string,
  source: EventSource,
  checkpoints: CheckpointStore,
  apply: (event: FishStockEvent) => Promise<void>,
): Promise<void> {
  const last = await checkpoints.read(name);
  const iter = source.subscribe(last);
  for await (const envelope of iter) {
    await apply(envelope.event);
    await checkpoints.write(name, envelope.position);
  }
}
