    case "SeafoodBatchCreated":
      if (raw.version === 1) {
        return { type: "SeafoodBatchCreated", id: raw.id, weightKg: raw.weight, origin: "unknown" };
      }
      if (raw.version === 2) {
        return { type: "SeafoodBatchCreated", id: raw.id, weightKg: raw.weightKg, origin: raw.origin };
      }
      throw new UnknownEventError(raw);
    case "SeafoodBatchShipped":
      if (raw.version === 1) {
        return { type: "SeafoodBatchShipped", id: raw.id, to: raw.to };
      }
      throw new UnknownEventError(raw);
    default: {
      const _never: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

export interface EventStore {
  readStream(stream: string): Promise<{ events: RawSeafoodBatchEvent[]; revision: bigint | "no_stream" }>;
}

export async function loadBatch(store: EventStore, stream: string): Promise<SeafoodBatchEvent[]> {
  const raw = await store.readStream(stream);
  return raw.events.map(upcast);
}
