  | { type: "SeafoodBatchCreated"; id: string; weightKg: number }
  | { type: "SeafoodBatchShipped"; id: string; to: string };

type SeafoodBatchCommand =
  | { type: "create"; id: string; weightKg: number }
  | { type: "ship"; to: string };

type SeafoodBatchState =
  | { status: "none" }
  | { status: "ready"; id: string; weightKg: number }
  | { status: "shipped"; id: string; to: string };

const initial: SeafoodBatchState = { status: "none" };

function evolve(state: SeafoodBatchState, event: SeafoodBatchEvent): SeafoodBatchState {
  switch (event.type) {
    case "SeafoodBatchCreated":
      return { status: "ready", id: event.id, weightKg: event.weightKg };
    case "SeafoodBatchShipped":
      return state.status === "ready" ? { status: "shipped", id: state.id, to: event.to } : state;
    default: {
      const _never: never = event;
      return state;
    }
  }
}

function decide(command: SeafoodBatchCommand, state: SeafoodBatchState): SeafoodBatchEvent[] {
  switch (command.type) {
    case "create":
      if (state.status !== "none") throw new Error("EXISTS");
      return [{ type: "SeafoodBatchCreated", id: command.id, weightKg: command.weightKg }];
    case "ship":
      if (state.status !== "ready") throw new Error("NOT_READY");
      return [{ type: "SeafoodBatchShipped", id: state.id, to: command.to }];
    default: {
      const _never: never = command;
      throw new Error("UNKNOWN");
    }
  }
}

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: ExpectedRevision }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: ExpectedRevision }): Promise<void>;
}

export interface BatchReadView {
  readonly id: string;
  readonly status: string;
  readonly destination?: string;
}

export interface BatchReadStore {
  get(id: string): Promise<BatchReadView | null>;
}

// Read model is eventually consistent with the event store.
export async function handleCommand(
  command: SeafoodBatchCommand,
  ctx: { streamName: string; eventStore: EventStore },
): Promise<void> {
  const current = await ctx.eventStore.readStream<SeafoodBatchEvent>(ctx.streamName);
  const state = current.events.reduce(evolve, initial);
  const events = decide(command, state);
  await ctx.eventStore.appendToStream<SeafoodBatchEvent>(ctx.streamName, events, { expectedRevision: current.revision });
}

export async function queryView(id: string, store: BatchReadStore): Promise<BatchReadView | null> {
  return store.get(id);
}
```

In CQRS, writes run through the aggregate: decide over loaded state, then appendToStream. Reads run through a view store updated by a projection. The two sides share only the event contract, never the aggregate state type. The read side is eventually consistent.

```typescript
export type NetPenEvent =
  | { type: "NetPenInstalled"; id: string; capacity: number }
  | { type: "NetPenLoaded"; id: string; count: number };

type NetPenCommand =
  | { type: "install"; id: string; capacity: number }
  | { type: "load"; count: number };

type NetPenState =
  | { status: "none" }
  | { status: "installed"; id: string; capacity: number; loaded: number };

const initial: NetPenState = { status: "none" };

function evolve(s: NetPenState, e: NetPenEvent): NetPenState {
  switch (e.type) {
    case "NetPenInstalled":
      return { status: "installed", id: e.id, capacity: e.capacity, loaded: 0 };
    case "NetPenLoaded":
      return s.status === "installed" ? { ...s, loaded: s.loaded + e.count } : s;
    default: {
      const _never: never = e;
      return s;
    }
  }
}

function decide(c: NetPenCommand, s: NetPenState): NetPenEvent[] {
  switch (c.type) {
    case "install":
      if (s.status !== "none") throw new Error("EXISTS");
      return [{ type: "NetPenInstalled", id: c.id, capacity: c.capacity }];
    case "load":
      if (s.status !== "installed") throw new Error("NOT_INSTALLED");
      return [{ type: "NetPenLoaded", id: s.id, count: c.count }];
    default: {
      const _never: never = c;
      throw new Error("UNKNOWN");
    }
  }
}

export interface EventStore {
  readStream<E>(s: string): Promise<{ events: E[]; revision: bigint | "no_stream" | "any" }>;
  appendToStream<E>(s: string, e: E[], o: { expectedRevision: bigint | "no_stream" | "any" }): Promise<void>;
}

export interface NetPenReadView { id: string; status: string; loaded: number }

export interface NetPenReadStore { get(id: string): Promise<NetPenReadView | null> }

// Read store trails the event store; fresh writes may not be visible yet.
export async function handleCommand(c: NetPenCommand, ctx: { streamName: string; eventStore: EventStore }): Promise<void> {
  const current = await ctx.eventStore.readStream<NetPenEvent>(ctx.streamName);
  const state = current.events.reduce(evolve, initial);
  const events = decide(c, state);
  await ctx.eventStore.appendToStream<NetPenEvent>(ctx.streamName, events, { expectedRevision: current.revision });
}

export async function queryView(id: string, reads: NetPenReadStore): Promise<NetPenReadView | null> {
  return reads.get(id);
}
