    case "HarvestWindowOpened":
      return { type: "ReserveProcessingLine", farmId: event.farmId };
    case "FishStockHarvested":
      return { type: "SettleHarvestInvoice", farmId: event.farmId, total: event.count };
    case "HarvestWindowClosed":
