  evolve(state, event) {
    switch (event.type) {
      case "NetPenInstalled":
        return { status: "installed", id: event.id, capacity: event.capacity, loaded: 0 };
      case "NetPenRetired":
        if (state.status !== "installed") return state;
        return { status: "retired", id: state.id };
      default: {
        const _never: never = event;
        return state;
