  decide(command, state) {
    switch (command.type) {
      case "seed":
        if (state.status !== "empty") throw new Error("EXISTS");
        return [{ type: "FishStockSeeded", id: command.id, count: command.count }];
      case "harvest":
        if (state.status !== "stocked") throw new Error("NOT_STOCKED");
        return [{ type: "FishStockHarvested", count: command.count }];
      case "audit":
        if (state.status !== "stocked") throw new Error("NOT_STOCKED");
        return [{ type: "FishStockAudited", by: command.by, at: command.at ?? "" }];
      default: {
        const _never: never = command;
        throw new Error("UNKNOWN");
