    switch (event.type) {
      case "FishStockSeeded":
        return { status: "stocked", id: event.id, count: event.count, audits: 0 };
      case "FishStockHarvested":
        return state.status === "stocked" ? { ...state, count: state.count - event.count } : state;
      case "FishStockAudited":
        return state.status === "stocked" ? { ...state, audits: state.audits + 1 } : state;
      default: {
        const _never: never = event;
        return state;
