  | { schema: "feeding.regime-ended.v1"; payload: { regimeId: string; endedAt: string } };

export function translate(event: FeedingRegimeEvent): IntegrationEvent | null {
  switch (event.type) {
    case "FeedingRegimeDefined":
      return null;
    case "FeedingRegimePaused":
      return null;
    case "FeedingRegimeStarted":
      return {
        schema: "feeding.regime-started.v1",
        payload: { regimeId: event.id, startedAt: event.at },
      };
    case "FeedingRegimeEnded":
      return {
        schema: "feeding.regime-ended.v1",
        payload: { regimeId: event.id, endedAt: event.at },
      };
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export interface OutboxSink {
  publish(event: IntegrationEvent): Promise<void>;
}

export async function appendToStream(sink: OutboxSink, events: FeedingRegimeEvent[]): Promise<void> {
  for (const event of events) {
    const integration = translate(event);
    if (integration !== null) await sink.publish(integration);
  }
}
